import SwiftUI
import PencilKit

struct HoverHighlightView: View {
    @State private var isHovering = false
    var body: some View {
        Rectangle()
            .fill(isHovering ? Color.blue.opacity(0.3) : Color.gray.opacity(0.1))
            .frame(height: 200)
            .onPencilHover { hovering in
                isHovering = hovering
            }
    }
}

